// WebClientConfig.java - Antes (hardcodeado)
@Configuration
public class WebClientConfig {
    @Bean
    public WebClient webClient() {
        return WebClient.builder()
            .baseUrl("http://localhost:8082")  // ❌ Hardcodeado
            .build();
    }
}

// WebClientConfig.java - Después (descubrimiento dinámico)
@Configuration
public class WebClientConfig {
    @Bean
    @LoadBalanced  // ✅ Habilita balanceo de carga
    public WebClient.Builder webClientBuilder() {
        return WebClient.builder();
    }

    @Bean
    public WebClient webClient(WebClient.Builder builder) {
        return builder
            .baseUrl("http://product-service")  // ✅ Nombre lógico
            .build();
    }
}

// CustomerService.java - Uso sigue igual
public Product getProduct(Long productId) {
    return webClient.get()
        .uri("/product/{id}", productId)  // Se resuelve a http://INSTANCE_IP:PORT/product/{id}
        .retrieve()
        .bodyToMono(Product.class)
        .block();
}

// Spring Cloud LoadBalancer resuelve automáticamente:
// http://product-service/product/1
// ↓
// Consulta Eureka por "PRODUCT-SERVICE"
// ↓
// Obtiene: [192.168.1.10:8082, 192.168.1.11:8082]
// ↓
// Selecciona: 192.168.1.10:8082 (round-robin)
// ↓
// Ejecuta: http://192.168.1.10:8082/product/1
